// Parse iCal feed and extract checkout events
const icalData = $input.first().json.data || $input.first().json.body || '';
const events = [];
const now = new Date();
const twoDaysFromNow = new Date(now.getTime() + 2 * 24 * 60 * 60 * 1000);

// Simple iCal parser
const eventBlocks = icalData.split('BEGIN:VEVENT');

for (let i = 1; i < eventBlocks.length; i++) {
  const block = eventBlocks[i];
  const getField = (name) => {
    const match = block.match(new RegExp(`${name}[^:]*:(.+)`));
    return match ? match[1].trim() : '';
  };

  const dtend = getField('DTEND');
  const dtstart = getField('DTSTART');
  const summary = getField('SUMMARY');
  const uid = getField('UID');
  const description = getField('DESCRIPTION');
  const location = getField('LOCATION');

  // Parse date (handle both DATE and DATETIME formats)
  const parseDate = (d) => {
    if (!d) return null;
    // Format: YYYYMMDD or YYYYMMDDTHHmmssZ
    const clean = d.replace(/[^0-9T]/g, '');
    if (clean.length === 8) {
      return new Date(`${clean.slice(0,4)}-${clean.slice(4,6)}-${clean.slice(6,8)}`);
    } else if (clean.includes('T')) {
      const datePart = clean.split('T')[0];
      return new Date(`${datePart.slice(0,4)}-${datePart.slice(4,6)}-${datePart.slice(6,8)}`);
    }
    return null;
  };

  const checkoutDate = parseDate(dtend);
  const checkinDate = parseDate(dtstart);

  if (checkoutDate && checkoutDate >= now && checkoutDate <= twoDaysFromNow) {
    // Calculate nights stayed
    let nights = 0;
    if (checkinDate && checkoutDate) {
      nights = Math.round((checkoutDate - checkinDate) / (1000 * 60 * 60 * 24));
    }

    events.push({
      uid: uid,
      summary: summary || 'Airbnb Booking',
      checkoutDate: checkoutDate.toISOString().split('T')[0],
      checkinDate: checkinDate ? checkinDate.toISOString().split('T')[0] : '',
      nights: nights,
      description: description,
      location: location,
      rawDtend: dtend,
      rawDtstart: dtstart,
      isToday: checkoutDate.toDateString() === now.toDateString(),
      isTomorrow: checkoutDate.toDateString() === new Date(now.getTime() + 24*60*60*1000).toDateString()
    });
  }
}

if (events.length === 0) {
  return [{ json: { noCheckouts: true, message: 'No upcoming checkouts in the next 48 hours' } }];
}

return events.map(e => ({ json: e }));

// Prepare dispatch payload for Workflow 2
const item = $input.first().json;

return [{
  json: {
    uid: item.uid,
    checkoutDate: item.checkoutDate,
    checkinDate: item.checkinDate,
    nights: item.nights,
    summary: item.summary,
    location: item.location || $env.NICK_DEFAULT_PROPERTY_ADDRESS || 'Address TBD',
    isToday: item.isToday,
    isTomorrow: item.isTomorrow,
    readyForDispatch: item.isToday || item.isTomorrow
  }
}];
